var webhookData = $input.first().json.body;
var base64Data = webhookData.csvData;
if (!base64Data) {
  throw new Error("No csvData found in request");
}

var datasetName = webhookData.datasetName || "Unnamed Dataset";
var description = webhookData.description || "";
var email = webhookData.email || "";

var csvText = Buffer.from(base64Data, "base64").toString("utf-8");

// Strip BOM if present
if (csvText.charCodeAt(0) === 0xFEFF) {
  csvText = csvText.slice(1);
}

// --- MULTILINE-AWARE CSV PARSER ---
function parseCSV(text) {
  const rows = [];
  let row = [];
  let cell = '';
  let inQuotes = false;

  for (let i = 0; i < text.length; i++) {
    const char = text[i];
    const next = text[i + 1];

    if (char === '"') {
      if (inQuotes && next === '"') {
        cell += '"';
        i++;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (char === ',' && !inQuotes) {
      row.push(cell.trim());
      cell = '';
    } else if (!inQuotes && (char === '\n' || char === '\r')) {
      if (char === '\r' && next === '\n') i++;
      row.push(cell.trim());
      if (row.some(v => v !== '')) {
        rows.push(row);
      }
      row = [];
      cell = '';
    } else {
      cell += char;
    }
  }

  // Flush final row
  if (cell || row.length) {
    row.push(cell.trim());
    if (row.some(v => v !== '')) {
      rows.push(row);
    }
  }

  return rows;
}
// ----------------------------------

var allRows = parseCSV(csvText);

if (allRows.length < 2) {
  throw new Error("CSV must have header and data rows");
}

var headers = allRows[0];
var rows = [];

for (var i = 1; i < allRows.length; i++) {
  var values = allRows[i];
  var row = {};
  for (var j = 0; j < headers.length; j++) {
    row[headers[j]] = values[j] !== undefined ? values[j] : "";
  }
  rows.push({ json: row });
}

if (rows.length === 0) {
  throw new Error("No data rows found");
}

$execution.customData.set("datasetName", datasetName);
$execution.customData.set("description", description);
$execution.customData.set("email", email);

return rows;

// 1. Fetch data safely
const datasetRecord = $('Get Dataset Record').first().json;
if (!datasetRecord || !datasetRecord.column_mapping) {
  throw new Error('Dataset not found or missing column_mapping');
}

const mapping = datasetRecord.column_mapping;
const webhookNode = $('Webhook').first();
const datasetId = webhookNode?.json?.body?.datasetId || 'default_id';
const allRows = $('Parse CSV').all();

// Safety: If no rows found, return empty array immediately to prevent n8n error
if (!allRows || allRows.length === 0) {
  return [];
}

const results = [];
const batchSize = 200;
const mapEntries = Object.entries(mapping);
const dbColumnNames = mapEntries.map(entry => entry[1]);

// 2. Helper Functions (No changes needed here)
function isDateColumn(colName) {
  const lower = colName.toLowerCase();
  const datePatterns = ['date', 'time', 'created', 'updated', 'timestamp', 'modified', 'expires', 'born', 'started', 'ended', 'due', 'scheduled', '_at', '_on'];
  return datePatterns.some(pattern => lower.indexOf(pattern) !== -1);
}

function isValidDateValue(val) {
  const stringVal = String(val).trim();
  const cleanNum = stringVal.replace(/,/g, '');
  if (/^\d+$/.test(cleanNum) && parseInt(cleanNum) > 9999) return false;
  return (stringVal.indexOf('/') !== -1 || stringVal.indexOf('-') !== -1);
}

function formatDateValue(val) {
  const stringVal = String(val).trim();
  const dateMatch = stringVal.match(/^(\d{1,4})[\/\-](\d{1,2})[\/\-](\d{1,4})(.*)$/);
  if (!dateMatch) return null;
  let year, month, day;
  const part1 = dateMatch[1], part2 = dateMatch[2], part3 = dateMatch[3], timePart = dateMatch[4] || '';

  if (part1.length === 4) { [year, month, day] = [part1, part2, part3]; }
  else if (part3.length === 4) {
    year = part3;
    if (parseInt(part1) > 12) { [day, month] = [part1, part2]; }
    else { [month, day] = [part1, part2]; }
  } else {
    year = parseInt(part3) > 50 ? '19' + part3 : '20' + part3;
    [month, day] = [part1, part2];
  }
  return `${year}-${('0' + month).slice(-2)}-${('0' + day).slice(-2)}${timePart}`;
}

function prepareValue(val, dbColumn) {
  if (val === null || val === undefined || String(val).trim() === '') return 'NULL';
  const stringVal = String(val).trim();
  const cleanNumericVal = stringVal.replace(/,/g, '');

  if (isDateColumn(dbColumn)) {
    if (!isValidDateValue(stringVal)) return 'NULL';
    const formatted = formatDateValue(stringVal);
    return formatted ? `'${formatted.replace(/'/g, "''")}'` : 'NULL';
  }

  if (/^-?[\d,]+(\.\d+)?$/.test(stringVal)) return cleanNumericVal;
  return `'${stringVal.replace(/'/g, "''")}'`;
}

// 3. Construct Batch SQL
const columns = ['"dataset_id"', '"row_index"'].concat(dbColumnNames.map(c => `"${c}"`));

for (let i = 0; i < allRows.length; i += batchSize) {
  const chunk = allRows.slice(i, i + batchSize);
  const valuesList = chunk.map((item, idx) => {
    const row = item.json;
    const rowValues = [`'${datasetId}'`, i + idx + 1];
    mapEntries.forEach(entry => {
      rowValues.push(prepareValue(row[entry[0]], entry[1]));
    });
    return `(${rowValues.join(',')})`;
  });

  // CRITICAL: Ensure the object strictly follows the { json: { ... } } pattern
  results.push({ 
    json: { 
      sql: `INSERT INTO n8n_data.universal_datatable (${columns.join(',')}) VALUES ${valuesList.join(',')};` 
    } 
  });
}

// 4. Return results (always returns an array)
return results;

